  1→import { describe, it, expect } from 'vitest';
  2→import { normalizeFrictionCategory } from './friction-normalize.js';
  3→
  4→// ──────────────────────────────────────────────────────
  5→// normalizeFrictionCategory
  6→// ──────────────────────────────────────────────────────
  7→
  8→describe('normalizeFrictionCategory', () => {
  9→  // ────────────────────────────────────────────────────
 10→  // Rule 1: Exact match (case-insensitive)
 11→  // ────────────────────────────────────────────────────
 12→
 13→  it('returns canonical for exact match', () => {
 14→    expect(normalizeFrictionCategory('knowledge-gap')).toBe('knowledge-gap');
 15→    expect(normalizeFrictionCategory('wrong-approach')).toBe('wrong-approach');
 16→    expect(normalizeFrictionCategory('stale-assumptions')).toBe('stale-assumptions');
 17→    expect(normalizeFrictionCategory('context-loss')).toBe('context-loss');
 18→    expect(normalizeFrictionCategory('scope-creep')).toBe('scope-creep');
 19→    expect(normalizeFrictionCategory('repeated-mistakes')).toBe('repeated-mistakes');
 20→  });
 21→
 22→  it('matches case-insensitively', () => {
 23→    expect(normalizeFrictionCategory('Knowledge-Gap')).toBe('knowledge-gap');
 24→    expect(normalizeFrictionCategory('WRONG-APPROACH')).toBe('wrong-approach');
 25→    expect(normalizeFrictionCategory('Stale-Assumptions')).toBe('stale-assumptions');
 26→  });
 27→
 28→  // ────────────────────────────────────────────────────
