 86→// Minimal session data needed for analysis (from SQLite sessions row)
 87→export interface SessionData {
 88→  id: string;
 89→  project_id: string;
 90→  project_name: string;
 91→  project_path: string;
 92→  summary: string | null;
 93→  ended_at: string;          // ISO 8601
 94→}
 95→
 96→/**
 97→ * Analyze a session and generate insights, saving them to SQLite.
 98→ */
 99→export async function analyzeSession(
100→  session: SessionData,
101→  messages: SQLiteMessageRow[],
102→  options?: AnalysisOptions
103→): Promise<AnalysisResult> {
104→  if (!isLLMConfigured()) {
105→    return {
106→      success: false,
107→      insights: [],
108→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
109→    };
110→  }
111→
112→  if (messages.length === 0) {
113→    return {
114→      success: false,
115→      insights: [],
116→      error: 'No messages found for this session.',
117→    };
118→  }
119→
120→  try {
121→    const client = createLLMClient();
122→    const formattedMessages = formatMessagesForAnalysis(messages);
123→    const estimatedTokens = client.estimateTokens(formattedMessages);
124→
125→    let analysisResponse: AnalysisResponse;
126→    let totalInputTokens = 0;
127→    let totalOutputTokens = 0;
128→
129→    if (estimatedTokens > MAX_INPUT_TOKENS) {
130→      // Chunk the messages and analyze separately
131→      const chunks = chunkMessages(messages, client.estimateTokens.bind(client));
132→      const chunkResponses: AnalysisResponse[] = [];
133→      const totalChunks = chunks.length;
134→
135→      for (let i = 0; i < chunks.length; i++) {
136→        const chunk = chunks[i];
137→        options?.onProgress?.({ phase: 'analyzing', currentChunk: i + 1, totalChunks });
138→
139→        const chunkFormatted = formatMessagesForAnalysis(chunk);
140→        const prompt = generateSessionAnalysisPrompt(
141→          session.project_name,
142→          session.summary,
143→          chunkFormatted
144→        );
145→
146→        const response = await client.chat([
147→          { role: 'system', content: SESSION_ANALYSIS_SYSTEM_PROMPT },
148→          { role: 'user', content: prompt },
149→        ], { signal: options?.signal });
150→
151→        if (response.usage) {
152→          totalInputTokens += response.usage.inputTokens;
153→          totalOutputTokens += response.usage.outputTokens;
154→        }
155→
156→        const parsed = parseAnalysisResponse(response.content);
157→        if (parsed.success) chunkResponses.push(parsed.data);
158→      }
159→
160→      if (chunkResponses.length === 0) {
161→        return {
162→          success: false,
163→          insights: [],
164→          error: 'All chunks failed to parse LLM response',
165→          error_type: 'json_parse_error',
166→          usage: { inputTokens: totalInputTokens, outputTokens: totalOutputTokens },
167→        };
168→      }
169→
170→      analysisResponse = mergeAnalysisResponses(chunkResponses);
171→
172→      // Chunked sessions: extract facets separately using dedicated facet prompt
173→      // (facets are holistic — can't be merged across chunks)
174→      if (!analysisResponse.facets) {
175→        try {
176→          // Use full conversation for best quality; truncate here if exceeding token limits
177→          let facetMessages = formatMessagesForAnalysis(messages);
178→          const facetTokens = client.estimateTokens(facetMessages);
179→          if (facetTokens > MAX_INPUT_TOKENS) {
180→            const targetLength = Math.floor((MAX_INPUT_TOKENS / facetTokens) * facetMessages.length * 0.8);
181→            facetMessages = facetMessages.slice(0, targetLength) + '\n\n[... conversation truncated for analysis ...]';
182→          }
183→          const facetPrompt = generateFacetOnlyPrompt(
184→            session.project_name,
185→            session.summary,
186→            facetMessages
187→          );
188→
189→          const facetResponse = await client.chat([
190→            { role: 'system', content: FACET_ONLY_SYSTEM_PROMPT },
191→            { role: 'user', content: facetPrompt },
192→          ], { signal: options?.signal });
193→
194→          if (facetResponse.usage) {
195→            totalInputTokens += facetResponse.usage.inputTokens;
196→            totalOutputTokens += facetResponse.usage.outputTokens;
197→          }
198→
199→          const facetJson = extractJsonPayload(facetResponse.content);
200→          if (facetJson) {
201→            try {
202→              analysisResponse.facets = JSON.parse(facetJson);
203→            } catch {
204→              // jsonrepair fallback
205→              try {
206→                analysisResponse.facets = JSON.parse(jsonrepair(facetJson));
207→              } catch {
208→                // Facet extraction failed for chunked session — non-fatal
209→              }
210→            }
211→          }
212→        } catch {
213→          // Facet extraction failed for chunked session — non-fatal, continue
214→        }
215→      }
216→    } else {
217→      options?.onProgress?.({ phase: 'analyzing', currentChunk: 1, totalChunks: 1 });
218→      const prompt = generateSessionAnalysisPrompt(
219→        session.project_name,
220→        session.summary,
221→        formattedMessages
222→      );
223→
224→      const response = await client.chat([
225→        { role: 'system', content: SESSION_ANALYSIS_SYSTEM_PROMPT },
226→        { role: 'user', content: prompt },
227→      ], { signal: options?.signal });
228→
229→      if (response.usage) {
230→        totalInputTokens = response.usage.inputTokens;
231→        totalOutputTokens = response.usage.outputTokens;
232→      }
233→
234→      const parsed = parseAnalysisResponse(response.content);
235→      if (!parsed.success) {
236→        return {
237→          success: false,
238→          insights: [],
239→          error: 'Failed to parse LLM response. Please try again.',
240→          error_type: parsed.error.error_type,
241→          response_length: parsed.error.response_length,
242→          response_preview: parsed.error.response_preview,
243→        };
244→      }
245→
246→      analysisResponse = parsed.data;
247→    }
248→
249→    options?.onProgress?.({ phase: 'saving' });
250→    const insights = convertToInsightRows(analysisResponse, session);
251→
252→    // Save new insights first, then delete old non-prompt-quality insights
253→    // (safe order: if save fails, old data is preserved)
254→    saveInsightsToDb(insights);
255→    deleteSessionInsights(session.id, {
256→      excludeTypes: ['prompt_quality'],
257→      excludeIds: insights.map(i => i.id),
258→    });
259→
260→    // Save facets if extracted
261→    if (analysisResponse.facets) {
262→      saveFacetsToDb(session.id, analysisResponse.facets, ANALYSIS_VERSION);
263→    }
264→
265→    return {
266→      success: true,
267→      insights,
268→      usage: { inputTokens: totalInputTokens, outputTokens: totalOutputTokens },
269→    };
270→  } catch (error) {
271→    if (error instanceof Error && error.name === 'AbortError') {
272→      return { success: false, insights: [], error: 'Analysis cancelled', error_type: 'abort' };
273→    }
274→    return {
275→      success: false,
276→      insights: [],
277→      error: error instanceof Error ? error.message : 'Analysis failed',
278→      error_type: 'api_error',
279→    };
280→  }
281→}
