398→/**
399→ * Find recurring patterns across multiple insights and write bidirectional links to SQLite.
400→ */
401→export async function findRecurringInsights(
402→  insights: Array<{
403→    id: string;
404→    type: string;
405→    title: string;
406→    summary: string;
407→    project_name: string;
408→    session_id: string;
409→  }>
410→): Promise<RecurringInsightResult> {
411→  if (!isLLMConfigured()) {
412→    return { success: false, groups: [], updatedCount: 0, error: 'LLM not configured.' };
413→  }
414→
415→  const candidates = insights
416→    .filter(i => i.type !== 'summary' && i.type !== 'prompt_quality')
417→    .slice(0, 200);
418→
419→  if (candidates.length < 2) {
420→    return {
421→      success: false,
422→      groups: [],
423→      updatedCount: 0,
424→      error: 'Need at least 2 non-summary insights to find patterns.',
425→    };
426→  }
427→
428→  try {
429→    const client = createLLMClient();
430→
431→    const insightData = candidates.map(i => ({
432→      id: i.id,
433→      type: i.type === 'technique' ? 'learning' : i.type,
434→      title: i.title,
435→      summary: i.summary.slice(0, 150),
436→      projectName: i.project_name,
437→      sessionId: i.session_id,
438→    }));
439→
440→    const prompt = `Analyze these insights from coding sessions and find groups of semantically similar or duplicate insights — ones that express the same learning or decision even if worded differently.
441→
442→RULES:
443→- Only group insights that are genuinely about the same concept/topic
444→- Insights in a group should be from DIFFERENT sessions (same sessionId = not recurring)
445→- A group must have at least 2 insights
446→- An insight can only belong to one group
447→- Provide a brief "theme" describing what the group shares
448→- If no recurring patterns exist, return an empty groups array
449→
450→INSIGHTS:
451→${JSON.stringify(insightData, null, 2)}
452→
453→Respond with valid JSON only:
454→{
455→  "groups": [
456→    {
457→      "insightIds": ["insight_abc", "insight_def"],
458→      "theme": "Brief description of the shared concept"
459→    }
460→  ]
461→}`;
462→
463→    const response = await client.chat([
464→      {
465→        role: 'system',
466→        content: 'You are an expert at identifying recurring patterns and themes across software development insights. You find semantically similar insights even when they are worded differently. Respond with valid JSON only.',
467→      },
468→      { role: 'user', content: prompt },
469→    ]);
470→
471→    const jsonMatch = response.content.match(/\{[\s\S]*\}/);
472→    if (!jsonMatch) {
473→      return { success: false, groups: [], updatedCount: 0, error: 'Failed to parse recurring insights response.' };
474→    }
475→
476→    const parsed = JSON.parse(jsonMatch[0]) as { groups: RecurringInsightGroup[] };
477→    const groups = parsed.groups || [];
478→
479→    const validIds = new Set(candidates.map(i => i.id));
480→    const validGroups = groups
481→      .map(g => ({
482→        ...g,
483→        insightIds: g.insightIds.filter(id => validIds.has(id)),
484→      }))
485→      .filter(g => g.insightIds.length >= 2);
486→
487→    if (validGroups.length === 0) {
488→      return {
489→        success: true,
490→        groups: [],
491→        updatedCount: 0,
492→        usage: response.usage
493→          ? { inputTokens: response.usage.inputTokens, outputTokens: response.usage.outputTokens }
494→          : undefined,
495→      };
496→    }
497→
498→    // Build bidirectional links
499→    const linkMap = new Map<string, string[]>();
500→    for (const group of validGroups) {
501→      for (const id of group.insightIds) {
502→        const others = group.insightIds.filter(otherId => otherId !== id);
503→        const existing = linkMap.get(id) || [];
504→        linkMap.set(id, [...new Set([...existing, ...others])]);
505→      }
506→    }
507→
508→    // Write links to SQLite
509→    const db = getDb();
510→    const updateLinks = db.prepare(
511→      `UPDATE insights SET linked_insight_ids = ? WHERE id = ?`
512→    );
513→
514→    for (const [insightId, linkedIds] of linkMap.entries()) {
515→      updateLinks.run(JSON.stringify(linkedIds), insightId);
516→    }
517→
518→    return {
519→      success: true,
520→      groups: validGroups,
521→      updatedCount: linkMap.size,
522→      usage: response.usage
523→        ? { inputTokens: response.usage.inputTokens, outputTokens: response.usage.outputTokens }
524→        : undefined,
525→    };
526→  } catch (error) {
527→    return {
528→      success: false,
529→      groups: [],
530→      updatedCount: 0,
531→      error: error instanceof Error ? error.message : 'Failed to find recurring insights',
532→    };
533→  }
534→}
