536→// --- Internal helpers ---
537→
538→function chunkMessages(
539→  messages: SQLiteMessageRow[],
540→  estimateTokens: (text: string) => number
541→): SQLiteMessageRow[][] {
542→  const chunks: SQLiteMessageRow[][] = [];
543→  let currentChunk: SQLiteMessageRow[] = [];
544→  let currentTokens = 0;
545→  const chunkLimit = MAX_INPUT_TOKENS * 0.8;
546→
547→  for (const message of messages) {
548→    let toolResults: Array<{ output?: string }> = [];
549→    try {
550→      toolResults = message.tool_results ? JSON.parse(message.tool_results) as Array<{ output?: string }> : [];
551→    } catch {
552→      toolResults = [];
553→    }
554→
555→    const messageText = [
556→      message.content,
557→      message.thinking?.slice(0, 1000) ?? '',
558→      ...toolResults.map(r => (r.output || '').slice(0, 500)),
559→    ].join(' ');
560→    const messageTokens = estimateTokens(messageText);
561→
562→    if (currentTokens + messageTokens > chunkLimit && currentChunk.length > 0) {
563→      chunks.push(currentChunk);
564→      currentChunk = [];
565→      currentTokens = 0;
566→    }
567→
568→    currentChunk.push(message);
569→    currentTokens += messageTokens;
570→  }
571→
572→  if (currentChunk.length > 0) {
573→    chunks.push(currentChunk);
574→  }
575→
576→  return chunks;
577→}
578→
579→function mergeAnalysisResponses(responses: AnalysisResponse[]): AnalysisResponse {
580→  if (responses.length === 0) {
581→    return {
582→      summary: { title: 'Analysis failed', content: '', bullets: [] },
583→      decisions: [],
584→      learnings: [],
585→    };
586→  }
587→
588→  if (responses.length === 1) return responses[0];
589→
590→  const merged: AnalysisResponse = {
591→    summary: responses[0].summary,
592→    decisions: [],
593→    learnings: [],
594→  };
595→
596→  for (const response of responses) {
597→    merged.decisions.push(...response.decisions);
598→    merged.learnings.push(...response.learnings);
599→  }
600→
601→  merged.decisions = deduplicateByTitle(merged.decisions).slice(0, 3);
602→  merged.learnings = deduplicateByTitle(merged.learnings).slice(0, 5);
603→
604→  return merged;
605→}
606→
607→function deduplicateByTitle<T extends { title: string }>(items: T[]): T[] {
608→  const seen = new Set<string>();
609→  return items.filter((item) => {
610→    const normalized = item.title.toLowerCase().trim();
611→    if (seen.has(normalized)) return false;
612→    seen.add(normalized);
613→    return true;
614→  });
615→}
616→
617→function convertToInsightRows(response: AnalysisResponse, session: SessionData): InsightRow[] {
618→  const insights: InsightRow[] = [];
619→  const now = new Date().toISOString();
620→
621→  insights.push({
622→    id: randomUUID(),
623→    session_id: session.id,
624→    project_id: session.project_id,
625→    project_name: session.project_name,
626→    type: 'summary',
627→    title: response.summary.title,
628→    content: response.summary.content,
629→    summary: response.summary.content,
630→    bullets: JSON.stringify(response.summary.bullets),
631→    confidence: 0.9,
632→    source: 'llm',
633→    metadata: response.summary.outcome
634→      ? JSON.stringify({ outcome: response.summary.outcome })
635→      : null,
636→    timestamp: session.ended_at,
637→    created_at: now,
638→    scope: 'session',
639→    analysis_version: ANALYSIS_VERSION,
640→  });
641→
642→  for (const decision of response.decisions) {
643→    const confidence = decision.confidence ?? 85;
644→    if (confidence < 70) continue;
645→
646→    const content = decision.situation && decision.choice
647→      ? `${decision.situation} → ${decision.choice}`
648→      : decision.choice || decision.situation || decision.title;
649→
650→    const altBullets = (decision.alternatives || [])
651→      .filter(a => a && typeof a === 'object' && a.option)
652→      .map(a => `${a.option}: ${a.rejected_because || 'no reason given'}`);
653→
654→    insights.push({
655→      id: randomUUID(),
656→      session_id: session.id,
657→      project_id: session.project_id,
658→      project_name: session.project_name,
659→      type: 'decision',
660→      title: decision.title,
661→      content,
662→      summary: (decision.choice || content).slice(0, 200),
663→      bullets: JSON.stringify(altBullets),
664→      confidence: confidence / 100,
665→      source: 'llm',
666→      metadata: JSON.stringify({
667→        situation: decision.situation,
668→        choice: decision.choice,
669→        reasoning: decision.reasoning,
670→        alternatives: decision.alternatives,
671→        trade_offs: decision.trade_offs,
672→        revisit_when: decision.revisit_when,
673→        evidence: decision.evidence,
674→      }),
675→      timestamp: session.ended_at,
676→      created_at: now,
677→      scope: 'session',
678→      analysis_version: ANALYSIS_VERSION,
679→    });
680→  }
681→
682→  for (const learning of response.learnings) {
683→    const confidence = learning.confidence ?? 80;
684→    if (confidence < 70) continue;
685→
686→    const content = learning.takeaway || learning.title;
687→
688→    insights.push({
689→      id: randomUUID(),
690→      session_id: session.id,
691→      project_id: session.project_id,
692→      project_name: session.project_name,
693→      type: 'learning',
694→      title: learning.title,
695→      content,
696→      summary: content.slice(0, 200),
697→      bullets: JSON.stringify([]),
698→      confidence: confidence / 100,
699→      source: 'llm',
700→      metadata: JSON.stringify({
701→        symptom: learning.symptom,
702→        root_cause: learning.root_cause,
703→        takeaway: learning.takeaway,
704→        applies_when: learning.applies_when,
705→        evidence: learning.evidence,
706→      }),
707→      timestamp: session.ended_at,
708→      created_at: now,
709→      scope: 'session',
710→      analysis_version: ANALYSIS_VERSION,
711→    });
712→  }
713→
714→  return insights;
715→}
716→
717→function convertPromptQualityToInsightRow(response: PromptQualityResponse, session: SessionData): InsightRow {
718→  const now = new Date().toISOString();
719→
720→  // Normalize categories at write time (mirrors saveFacetsToDb pattern)
721→  const normalizedFindings = response.findings.map(f => ({
722→    ...f,
723→    category: f.category ? normalizePromptQualityCategory(f.category) : 'uncategorized',
724→  }));
725→
726→  const normalizedTakeaways = response.takeaways.map(t => ({
727→    ...t,
728→    category: t.category ? normalizePromptQualityCategory(t.category) : 'uncategorized',
729→  }));
730→
731→  return {
732→    id: randomUUID(),
733→    session_id: session.id,
734→    project_id: session.project_id,
735→    project_name: session.project_name,
736→    type: 'prompt_quality',
737→    title: `Prompt Efficiency: ${response.efficiency_score}/100`,
738→    content: response.assessment,
739→    summary: response.assessment,
740→    bullets: JSON.stringify([]),  // takeaways live in metadata.takeaways; bullets expects string[] for other insight types
741→    confidence: 0.85,
742→    source: 'llm',
743→    metadata: JSON.stringify({
744→      efficiency_score: response.efficiency_score,
745→      message_overhead: response.message_overhead,
746→      takeaways: normalizedTakeaways,
747→      findings: normalizedFindings,
748→      dimension_scores: response.dimension_scores,
749→    }),
750→    timestamp: session.ended_at,
751→    created_at: now,
752→    scope: 'session',
753→    analysis_version: ANALYSIS_VERSION,
754→  };
755→}
756→
757→/**
758→ * Write insight rows to SQLite using prepared statements.
759→ */
760→function saveInsightsToDb(insights: InsightRow[]): void {
761→  const db = getDb();
762→  const insert = db.prepare(`
763→    INSERT OR REPLACE INTO insights (
764→      id, session_id, project_id, project_name, type, title, content,
765→      summary, bullets, confidence, source, metadata, timestamp,
766→      created_at, scope, analysis_version
767→    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
768→  `);
769→
770→  const insertMany = db.transaction((rows: InsightRow[]) => {
771→    for (const row of rows) {
772→      insert.run(
773→        row.id,
774→        row.session_id,
775→        row.project_id,
776→        row.project_name,
777→        row.type,
778→        row.title,
779→        row.content,
780→        row.summary,
781→        row.bullets,
782→        row.confidence,
783→        row.source,
784→        row.metadata,
785→        row.timestamp,
786→        row.created_at,
787→        row.scope,
788→        row.analysis_version,
789→      );
790→    }
791→  });
792→
793→  insertMany(insights);
794→}
795→
796→interface DeleteOptions {
797→  excludeTypes?: string[];
798→  includeOnlyTypes?: string[];
799→  excludeIds?: string[];
800→}
801→
802→/**
803→ * Delete insights for a session, with optional type and ID exclusions.
804→ */
805→function deleteSessionInsights(sessionId: string, opts: DeleteOptions): void {
806→  const db = getDb();
807→  const conditions: string[] = ['session_id = ?'];
808→  const params: (string | number)[] = [sessionId];
809→
810→  if (opts.excludeTypes && opts.excludeTypes.length > 0) {
811→    conditions.push(`type NOT IN (${opts.excludeTypes.map(() => '?').join(', ')})`);
812→    params.push(...opts.excludeTypes);
813→  }
814→
815→  if (opts.includeOnlyTypes && opts.includeOnlyTypes.length > 0) {
816→    conditions.push(`type IN (${opts.includeOnlyTypes.map(() => '?').join(', ')})`);
817→    params.push(...opts.includeOnlyTypes);
818→  }
819→
820→  if (opts.excludeIds && opts.excludeIds.length > 0) {
821→    conditions.push(`id NOT IN (${opts.excludeIds.map(() => '?').join(', ')})`);
822→    params.push(...opts.excludeIds);
823→  }
824→
825→  db.prepare(`DELETE FROM insights WHERE ${conditions.join(' AND ')}`).run(...params);
826→}
827→
828→/**
829→ * Save extracted facets to the session_facets table.
830→ */
831→function saveFacetsToDb(
832→  sessionId: string,
833→  facets: NonNullable<AnalysisResponse['facets']>,
834→  analysisVersion: string
835→): void {
836→  const db = getDb();
837→
838→  // Normalize pattern categories at write time so stored data is always clean.
839→  // This handles LLM variants (e.g., "task-decomposition" → "structured-planning")
840→  // before they hit the database, keeping aggregation queries simple.
841→  const normalizedPatterns = Array.isArray(facets.effective_patterns)
842→    ? facets.effective_patterns.map(ep => {
843→        if (!ep.category) {
844→          // Should not happen with updated prompts — indicates model ignored category instruction.
845→          // Fall back to 'uncategorized' so these sessions don't trigger the outdated banner.
846→          console.warn('[pattern-monitor] saveFacetsToDb: effective_pattern missing category field, defaulting to uncategorized');
847→        }
848→        return {
849→          ...ep,
850→          category: ep.category ? normalizePatternCategory(ep.category) : 'uncategorized',
851→        };
852→      })
853→    : [];
854→
855→  db.prepare(`
856→    INSERT OR REPLACE INTO session_facets
857→    (session_id, outcome_satisfaction, workflow_pattern, had_course_correction,
858→     course_correction_reason, iteration_count, friction_points, effective_patterns,
859→     analysis_version)
860→    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
861→  `).run(
862→    sessionId,
863→    facets.outcome_satisfaction,
864→    facets.workflow_pattern,
865→    facets.had_course_correction ? 1 : 0,
866→    facets.course_correction_reason,
867→    facets.iteration_count,
868→    JSON.stringify(Array.isArray(facets.friction_points) ? facets.friction_points : []),
869→    JSON.stringify(normalizedPatterns),
870→    analysisVersion
871→  );
872→}
873→
874→/**
875→ * Extract facets only for a session that already has insights (backfill).
876→ * Uses the full conversation transcript for accurate friction attribution.
877→ * Falls back to truncation for sessions exceeding token limits.
878→ */
879→export async function extractFacetsOnly(
880→  session: SessionData,
881→  messages: SQLiteMessageRow[],
882→  options?: { signal?: AbortSignal }
883→): Promise<{ success: boolean; error?: string }> {
884→  if (!isLLMConfigured()) {
885→    return { success: false, error: 'LLM not configured.' };
886→  }
887→
888→  if (messages.length === 0) {
889→    return { success: false, error: 'No messages found.' };
890→  }
891→
892→  try {
893→    const client = createLLMClient();
894→    let formattedMessages = formatMessagesForAnalysis(messages);
895→
896→    // Truncate if conversation exceeds token limits (same pattern as PQ analysis)
897→    const estimatedTokens = client.estimateTokens(formattedMessages);
898→    if (estimatedTokens > MAX_INPUT_TOKENS) {
899→      const targetLength = Math.floor((MAX_INPUT_TOKENS / estimatedTokens) * formattedMessages.length * 0.8);
900→      formattedMessages = formattedMessages.slice(0, targetLength) + '\n\n[... conversation truncated for analysis ...]';
901→    }
902→
903→    const prompt = generateFacetOnlyPrompt(
904→      session.project_name,
905→      session.summary,
906→      formattedMessages
907→    );
908→
909→    const response = await client.chat([
910→      { role: 'system', content: FACET_ONLY_SYSTEM_PROMPT },
911→      { role: 'user', content: prompt },
912→    ], { signal: options?.signal });
913→
914→    const jsonPayload = extractJsonPayload(response.content);
915→    if (!jsonPayload) {
916→      return { success: false, error: 'No JSON in facet response.' };
917→    }
918→
919→    let facets: AnalysisResponse['facets'];
920→    try {
921→      facets = JSON.parse(jsonPayload);
922→    } catch {
923→      facets = JSON.parse(jsonrepair(jsonPayload));
924→    }
925→
926→    if (facets) {
927→      saveFacetsToDb(session.id, facets, ANALYSIS_VERSION);
928→    }
929→
930→    return { success: true };
931→  } catch (error) {
932→    if (error instanceof Error && error.name === 'AbortError') {
933→      return { success: false, error: 'Cancelled' };
934→    }
935→    return {
936→      success: false,
937→      error: error instanceof Error ? error.message : 'Facet extraction failed',
