242→
243→    const systemPrompt = getExportSystemPrompt(ctx);
244→    const insightContext = buildInsightContext(capped);
245→    const userPrompt = buildExportUserPrompt(ctx, insightContext);
246→
247→    const client = createLLMClient();
248→    const response = await client.chat([
249→      { role: 'system', content: systemPrompt },
250→      { role: 'user', content: userPrompt },
251→    ], { signal: c.req.raw.signal });
252→
253→    const metadata: ExportGenerateMetadata = {
254→      insightCount: capped.length,
255→      totalInsights,
256→      sessionCount: sessionCtx.sessionCount,
257→      projectCount: sessionCtx.projectCount,
258→      scope,
259→      depth,
260→    };
261→
262→    trackEvent('export_run', {
263→      format: `llm-${format}`,
264→      scope,
265→      depth,
266→      insight_count: capped.length,
267→      session_count: sessionCtx.sessionCount,
268→      llm_provider: llmConfig?.provider,
269→      llm_model: llmConfig?.model,
270→      duration_ms: Date.now() - startTime,
