278→      return c.json({ error: 'Export cancelled' }, 422);
279→    }
280→    const message = error instanceof Error ? error.message : 'Export generation failed';
281→    captureError(error, { format, scope, depth, llm_provider: llmConfig?.provider, llm_model: llmConfig?.model });
282→    trackEvent('export_run', {
283→      format: `llm-${format}`,
284→      scope,
285→      depth,
286→      llm_provider: llmConfig?.provider,
287→      llm_model: llmConfig?.model,
288→      duration_ms: Date.now() - startTime,
289→      success: false,
