297→// SSE endpoint — streams progress events during LLM export generation.
298→// onProgress is implicit (no chunked analysis here); stream.writeSSE is fire-and-forget
299→// for progress events (non-fatal if missed).
300→app.get('/generate/stream', async (c) => {
301→  if (!isLLMConfigured()) {
302→    return c.json({
