341→          phase: 'loading_insights',
342→          insightCount: capped.length,
343→          totalInsights,
344→        }),
345→      });
346→
347→      if (capped.length === 0) {
348→        await stream.writeSSE({
349→          event: 'error',
350→          data: JSON.stringify({ error: 'No insights found for the selected scope. Run analysis on some sessions first.' }),
351→        });
352→        return;
353→      }
354→
355→      // Phase 2: synthesizing
356→      void stream.writeSSE({
357→        event: 'progress',
358→        data: JSON.stringify({ phase: 'synthesizing', progress: 'Sending to LLM...' }),
359→      }).catch(() => {});
360→
361→      const sessionCtx = fetchSessionContext(db, scope, projectId);
362→      const ctx = {
363→        scope,
364→        format,
365→        depth,
366→        projectName: sessionCtx.projectName,
367→        sessionCount: sessionCtx.sessionCount,
368→        projectCount: sessionCtx.projectCount,
369→        dateRange: { from: sessionCtx.dateFrom, to: sessionCtx.dateTo },
370→        exportDate: new Date().toISOString().slice(0, 10),
371→      };
372→
373→      const systemPrompt = getExportSystemPrompt(ctx);
374→      const insightContext = buildInsightContext(capped);
375→      const userPrompt = buildExportUserPrompt(ctx, insightContext);
376→
377→      const client = createLLMClient();
