379→        { role: 'system', content: systemPrompt },
380→        { role: 'user', content: userPrompt },
381→      ], { signal: abortSignal });
382→
383→      const metadata: ExportGenerateMetadata = {
384→        insightCount: capped.length,
385→        totalInsights,
386→        sessionCount: sessionCtx.sessionCount,
387→        projectCount: sessionCtx.projectCount,
388→        scope,
389→        depth,
390→      };
391→
392→      trackEvent('export_run', {
393→        format: `llm-${format}`,
394→        scope,
395→        depth,
396→        insight_count: capped.length,
