  1→import { Hono } from 'hono';
  2→import { streamSSE } from 'hono/streaming';
  3→import { getDb } from '@code-insights/cli/db/client';
  4→import { trackEvent, captureError } from '@code-insights/cli/utils/telemetry';
  5→import { parseIntParam } from '../utils.js';
  6→import { loadLLMConfig, isLLMConfigured } from '../llm/client.js';
  7→import { analyzeSession, analyzePromptQuality, findRecurringInsights } from '../llm/analysis.js';
  8→import type { SQLiteMessageRow, SessionData } from '../llm/analysis.js';
  9→
 10→const app = new Hono();
 11→
 12→/** Auto-apply an LLM-generated summary title as the session's generated_title. */
 13→function applyGeneratedTitle(sessionId: string, insights: Array<{ type: string; title?: string }>) {
 14→  const summaryInsight = insights.find(i => i.type === 'summary');
 15→  if (!summaryInsight?.title) return;
 16→  const db = getDb();
 17→  db.prepare('UPDATE sessions SET generated_title = ? WHERE id = ? AND deleted_at IS NULL')
 18→    .run(summaryInsight.title.slice(0, 120), sessionId);
 19→}
 20→
 21→// POST /api/analysis/session
 22→// Body: { sessionId: string }
 23→// Fetches session + messages from SQLite, runs LLM analysis, saves insights, returns results.
 24→app.post('/session', async (c) => {
 25→  if (!isLLMConfigured()) {
 26→    return c.json({
 27→      success: false,
 28→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
 29→    }, 400);
 30→  }
 31→
 32→  const body = await c.req.json<{ sessionId?: string }>();
 33→  if (!body.sessionId || typeof body.sessionId !== 'string') {
 34→    return c.json({ error: 'Missing required field: sessionId' }, 400);
 35→  }
 36→
 37→  const db = getDb();
 38→
 39→  const session = db.prepare(`
 40→    SELECT id, project_id, project_name, project_path, summary, ended_at
 41→    FROM sessions WHERE id = ? AND deleted_at IS NULL
 42→  `).get(body.sessionId) as SessionData | undefined;
 43→
 44→  if (!session) {
 45→    return c.json({ error: 'Session not found' }, 404);
 46→  }
 47→
 48→  const messages = db.prepare(`
 49→    SELECT id, session_id, type, content, thinking, tool_calls, tool_results, usage, timestamp, parent_id
 50→    FROM messages WHERE session_id = ? ORDER BY timestamp ASC
 51→  `).all(body.sessionId) as SQLiteMessageRow[];
 52→
 53→  const llmConfig = loadLLMConfig();
 54→  const startTime = Date.now();
 55→  const result = await analyzeSession(session, messages);
 56→  const baseProperties = {
 57→    type: 'session',
 58→    llm_provider: llmConfig?.provider,
 59→    llm_model: llmConfig?.model,
 60→    duration_ms: Date.now() - startTime,
 61→    success: result.success,
 62→  };
 63→  if (!result.success) {
 64→    const errorProperties = {
 65→      ...baseProperties,
 66→      error_type: result.error_type,
 67→      error_message: result.error,
 68→      response_preview: result.response_preview,
 69→    };
 70→    trackEvent('analysis_run', errorProperties);
 71→    captureError(new Error(result.error ?? 'analysis_run failed'), errorProperties);
 72→  } else {
 73→    trackEvent('analysis_run', baseProperties);
 74→    trackEvent('insight_generated', {
 75→      type: 'session',
 76→      count: result.insights.length,
 77→    });
 78→    applyGeneratedTitle(body.sessionId, result.insights);
 79→  }
 80→  return c.json(result, result.success ? 200 : 422);
 81→});
 82→
 83→// GET /api/analysis/session/stream?sessionId=X
 84→// SSE endpoint — streams progress events during session analysis.
 85→// onProgress is non-async because analyzeSession calls it without await;
 86→// stream.writeSSE is fire-and-forget for progress events (non-fatal if missed).
 87→app.get('/session/stream', async (c) => {
 88→  if (!isLLMConfigured()) {
 89→    return c.json({
 90→      success: false,
 91→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
 92→    }, 400);
 93→  }
 94→
 95→  const sessionId = c.req.query('sessionId');
 96→  if (!sessionId) {
 97→    return c.json({ error: 'Missing required query param: sessionId' }, 400);
 98→  }
 99→
100→  const db = getDb();
101→
102→  const session = db.prepare(`
103→    SELECT id, project_id, project_name, project_path, summary, ended_at
104→    FROM sessions WHERE id = ? AND deleted_at IS NULL
105→  `).get(sessionId) as SessionData | undefined;
106→
107→  if (!session) {
108→    return c.json({ error: 'Session not found' }, 404);
109→  }
