  1→import { Hono } from 'hono';
  2→import { streamSSE } from 'hono/streaming';
  3→import { getDb } from '@code-insights/cli/db/client';
  4→import { trackEvent, captureError } from '@code-insights/cli/utils/telemetry';
  5→import type { ExportTemplate } from '@code-insights/cli/types';
  6→import { formatKnowledgeBase } from '../export/knowledge-base.js';
  7→import { formatAgentRules } from '../export/agent-rules.js';
  8→import type { SessionRow, InsightRow } from '../export/knowledge-base.js';
  9→import { createLLMClient, isLLMConfigured, loadLLMConfig } from '../llm/client.js';
 10→import {
 11→  applyDepthCap,
 12→  buildInsightContext,
 13→  getExportSystemPrompt,
 14→  buildExportUserPrompt,
 15→  type ExportFormat,
 16→  type ExportScope,
 17→  type ExportDepth,
 18→  type ExportInsightRow,
 19→} from '../llm/export-prompts.js';
 20→
 21→const app = new Hono();
 22→
 23→// SQLite SQLITE_LIMIT_VARIABLE_NUMBER is 999 by default.
 24→// Batch insights queries to avoid hitting this limit for large session sets.
 25→const INSIGHTS_BATCH_SIZE = 500;
 26→
 27→function fetchInsightsForSessions(db: ReturnType<typeof getDb>, sessionIds: string[]): InsightRow[] {
 28→  if (sessionIds.length === 0) return [];
 29→
 30→  const results: InsightRow[] = [];
 31→  for (let i = 0; i < sessionIds.length; i += INSIGHTS_BATCH_SIZE) {
 32→    const chunk = sessionIds.slice(i, i + INSIGHTS_BATCH_SIZE);
 33→    const placeholders = chunk.map(() => '?').join(', ');
 34→    const rows = db.prepare(
 35→      `SELECT id, session_id, project_id, project_name, type, title, content,
 36→              summary, bullets, confidence, source, metadata, timestamp,
 37→              created_at, scope, analysis_version, linked_insight_ids
 38→       FROM insights WHERE session_id IN (${placeholders})
 39→       ORDER BY type, timestamp`,
 40→    ).all(...chunk) as InsightRow[];
 41→    results.push(...rows);
 42→  }
 43→  return results;
 44→}
 45→
 46→// POST /api/export/markdown — export sessions/insights as markdown
 47→app.post('/markdown', async (c) => {
 48→  const db = getDb();
 49→  const body = await c.req.json<{
 50→    sessionIds?: string[];
 51→    projectId?: string;
 52→    template?: ExportTemplate;
 53→  }>();
 54→
 55→  const { sessionIds, projectId, template = 'knowledge-base' } = body;
 56→
 57→  if (template !== 'knowledge-base' && template !== 'agent-rules') {
 58→    return c.json({ error: 'template must be "knowledge-base" or "agent-rules"' }, 400);
 59→  }
 60→  if (sessionIds !== undefined && !Array.isArray(sessionIds)) {
 61→    return c.json({ error: 'sessionIds must be an array' }, 400);
 62→  }
 63→  if (sessionIds && (sessionIds as unknown[]).some((id) => typeof id !== 'string')) {
 64→    return c.json({ error: 'sessionIds must contain only strings' }, 400);
 65→  }
 66→  if (sessionIds && sessionIds.length > 100) {
 67→    return c.json({ error: 'Maximum 100 session IDs per export request' }, 400);
 68→  }
 69→
 70→  let sessions: SessionRow[];
 71→  if (sessionIds && sessionIds.length > 0) {
 72→    const placeholders = sessionIds.map(() => '?').join(', ');
 73→    sessions = db.prepare(
 74→      `SELECT id, project_name, generated_title, custom_title, started_at, ended_at,
 75→              message_count, estimated_cost_usd, session_character, source_tool
 76→       FROM sessions WHERE id IN (${placeholders}) AND deleted_at IS NULL ORDER BY started_at DESC`,
 77→    ).all(...sessionIds) as SessionRow[];
 78→  } else if (projectId) {
 79→    // Cap at 100 to avoid unbounded queries and SQLite variable limit on insight fetch
 80→    sessions = db.prepare(
 81→      `SELECT id, project_name, generated_title, custom_title, started_at, ended_at,
 82→              message_count, estimated_cost_usd, session_character, source_tool
 83→       FROM sessions WHERE project_id = ? AND deleted_at IS NULL ORDER BY started_at DESC LIMIT 100`,
 84→    ).all(projectId) as SessionRow[];
 85→  } else {
 86→    // "Everything" export — most recent 100 sessions
 87→    sessions = db.prepare(
 88→      `SELECT id, project_name, generated_title, custom_title, started_at, ended_at,
 89→              message_count, estimated_cost_usd, session_character, source_tool
 90→       FROM sessions WHERE deleted_at IS NULL ORDER BY started_at DESC LIMIT 100`,
 91→    ).all() as SessionRow[];
 92→  }
 93→
 94→  const insights = fetchInsightsForSessions(db, sessions.map((s) => s.id));
 95→
 96→  const markdown =
 97→    template === 'agent-rules'
 98→      ? formatAgentRules(sessions, insights)
 99→      : formatKnowledgeBase(sessions, insights);
100→
101→  trackEvent('export_run', {
102→    format: 'markdown',
103→    template,
104→    session_count: sessions.length,
105→    insight_count: insights.length,
106→    success: true,
107→  });
108→
109→  c.header('Content-Type', 'text/markdown');
110→  return c.body(markdown);
111→});
112→
113→// ─── LLM-powered export types (co-located, not in cli/src/types.ts) ──────────
114→
115→interface ExportGenerateBody {
116→  scope: ExportScope;
117→  projectId?: string;
118→  format: ExportFormat;
119→  depth?: ExportDepth;
120→}
121→
122→interface ExportGenerateMetadata {
123→  insightCount: number;    // insights actually sent to LLM
124→  totalInsights: number;   // total insights available for scope
125→  sessionCount: number;
126→  projectCount: number;
127→  scope: ExportScope;
128→  depth: ExportDepth;
129→}
130→
131→// Fetch scoped insights ordered by confidence DESC, timestamp DESC.
132→// Excludes 'summary' type — per-session summaries aren't cross-session knowledge.
133→function fetchScopedInsights(
134→  db: ReturnType<typeof getDb>,
135→  scope: ExportScope,
136→  projectId: string | undefined
137→): ExportInsightRow[] {
138→  if (scope === 'project') {
139→    if (!projectId) return [];
140→    return db.prepare(`
141→      SELECT i.id, i.type, i.title, i.content, i.summary, i.confidence, i.project_name, i.timestamp
142→      FROM insights i
143→      JOIN sessions s ON i.session_id = s.id AND s.deleted_at IS NULL
144→      WHERE i.project_id = ? AND i.type != 'summary'
145→      ORDER BY i.confidence DESC, i.timestamp DESC
146→    `).all(projectId) as ExportInsightRow[];
147→  }
148→
149→  return db.prepare(`
150→    SELECT i.id, i.type, i.title, i.content, i.summary, i.confidence, i.project_name, i.timestamp
151→    FROM insights i
152→    JOIN sessions s ON i.session_id = s.id AND s.deleted_at IS NULL
153→    WHERE i.type != 'summary'
154→    ORDER BY i.confidence DESC, i.timestamp DESC
155→  `).all() as ExportInsightRow[];
156→}
157→
158→function fetchSessionContext(
159→  db: ReturnType<typeof getDb>,
160→  scope: ExportScope,
161→  projectId: string | undefined
162→): { sessionCount: number; projectCount: number; projectName: string | undefined; dateFrom: string; dateTo: string } {
163→  const today = new Date().toISOString().slice(0, 10);
164→
165→  if (scope === 'project' && projectId) {
166→    const row = db.prepare(`
167→      SELECT COUNT(*) as cnt, MIN(started_at) as min_date, MAX(ended_at) as max_date, project_name
168→      FROM sessions WHERE project_id = ? AND deleted_at IS NULL
169→    `).get(projectId) as { cnt: number; min_date: string; max_date: string; project_name: string } | undefined;
170→    return {
171→      sessionCount: row?.cnt ?? 0,
172→      projectCount: 1,
173→      projectName: row?.project_name,
174→      dateFrom: row?.min_date?.slice(0, 10) ?? today,
175→      dateTo: row?.max_date?.slice(0, 10) ?? today,
176→    };
177→  }
178→
179→  const row = db.prepare(`
180→    SELECT COUNT(*) as session_cnt,
181→           COUNT(DISTINCT project_id) as project_cnt,
182→           MIN(started_at) as min_date,
183→           MAX(ended_at) as max_date
184→    FROM sessions
185→    WHERE deleted_at IS NULL
186→  `).get() as { session_cnt: number; project_cnt: number; min_date: string; max_date: string } | undefined;
187→
188→  return {
189→    sessionCount: row?.session_cnt ?? 0,
190→    projectCount: row?.project_cnt ?? 0,
191→    projectName: undefined,
192→    dateFrom: row?.min_date?.slice(0, 10) ?? today,
193→    dateTo: row?.max_date?.slice(0, 10) ?? today,
194→  };
195→}
196→
197→// POST /api/export/generate
198→// Synchronous LLM export — returns full result when complete.
199→app.post('/generate', async (c) => {
200→  if (!isLLMConfigured()) {
201→    return c.json({
202→      success: false,
203→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
204→    }, 400);
205→  }
206→
207→  const body = await c.req.json<ExportGenerateBody>();
208→  const { scope, projectId, format, depth = 'standard' } = body;
209→
210→  if (scope !== 'project' && scope !== 'all') {
